import { useEffect, useState, lazy, Suspense } from "react";
import Navbar from "./componets/Navbar";

const navigation = {
  go: (view) => (window.location.href = `#/?view=${view}`),
  back: () => window.history.back(),
};

function App() {
  const [view, setView] = useState("Home");
  const [isAuth, setAuth] = useState(false);

  useEffect(() => {
    if (!window.document.cookie.isAuth) {
      setView("Login");
    }
  }, []);

  const handlerRouter = (event) => {
    let isAuth = "off";
    isAuth = document.cookie.match(new RegExp("(^| )isAuth=([^;]+)"));
    if (isAuth !== null) {
      isAuth = isAuth[2];
    }

    if (isAuth === "on") {
      const params = event.target.location.href.split("?")[1];
      const urlParams = new URLSearchParams(params);
      const _view = urlParams.get("view") || "Clients";
      setAuth(true);
      setView(_view);
    } else {
      window.history.pushState("login", "Login Page", "/#?view=Login");
      setAuth(false);
      setView("Login");
    }
  };

  window.addEventListener("load", handlerRouter);
  window.addEventListener("popstate", handlerRouter);

  const View = lazy(async () => await import(`./views/${view}`));
  return (
    <>
      {view !== "Login" && <Navbar navigation={navigation} />}
      <Suspense fallback={<div>Loading....</div>}>
        <View navigation={navigation} isAuth={isAuth} />
      </Suspense>
    </>
  );
}

export default App;
